output:
    path = self._job_path(job_id)
    if not path.is_file():
        raise GovernedError(f"Job not found: {job_id}")
    job = load_json(path)
    if not isinstance(job, dict) or job.get("job_id") != job_id:
        raise GovernedError(f"Invalid job record: {job_id}")
    return job

def _save_job(self, job: dict[str, Any]) -> None:
    job = copy.deepcopy(job)
    job["updated_at"] = iso_now()
    atomic_write_json(self._job_path(str(job["job_id"])), job)

def _controller_state_path(self) -> Path:
    return self.repo / "memory/phase-controller/controller.json"

def _load_controller_state(self) -> dict[str, Any]:
    path = self._controller_state_path()
    if not path.is_file():
        raise GovernedError("Controller state file is missing")
    state = load_json(path)
    if not isinstance(state, dict):
        raise GovernedError("Invalid controller state")
    return state

def _workspace(self, job_id: str, run_id: str | None = None, *, create: bool = False) -> Path:
    rid = run_id or f"run-{utc_stamp()}-{uuid.uuid4().hex[:8]}"
    if not re.fullmatch(r"[A-Za-z0-9._-]+", rid):
        raise GovernedError("Invalid run_id")
    workspace = self.staging_root / job_id / rid
    if create:
        workspace.mkdir(parents=True, exist_ok=False)
    return workspace

def _latest_workspace(self, job_id: str) -> Path:
    root = self.staging_root / job_id
    if not root.is_dir():
        raise GovernedError(f"No governed workspace for {job_id}")
    runs = sorted((p for p in root.iterdir() if p.is_dir()), key=lambda p: p.name)
    if not runs:
        raise GovernedError(f"No governed runs for {job_id}")
    return runs[-1]

def _workspace_from_request(self, req: dict[str, Any]) -> Path:
    job_id = self._safe_job_id(req.get("job_id"))
    run_id = req.get("run_id")
    return self._workspace(job_id, run_id) if run_id else self._latest_workspace(job_id)

def _snapshot_paths(self, label: str, paths: list[str]) -> Path:
    backup = self.backup_root / f"{label}-{utc_stamp()}-{uuid.uuid4().hex[:6]}"
    files_root = backup / "files"
    manifest: list[dict[str, Any]] = []
    for raw in paths:
        rel, live = self._safe_rel(raw, purpose="target")
        entry: dict[str, Any] = {"path": str(rel), "exists": live.exists()}
        if live.is_file():
            dest = files_root / rel
            dest.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(live, dest)
            entry.update({"sha256": sha256_file(live), "size": live.stat().st_size})
        elif live.exists():
            raise GovernedError(f"Snapshot target must be a file: {raw}")
        manifest.append(entry)
    backup.mkdir(parents=True, exist_ok=True)
    atomic_write_json(
        backup / "manifest.json",
        {
            "schema_version": "1.0",
            "created_at": iso_now(),
            "label": label,
            "repository": str(self.repo),
            "files": manifest,
        },
    )
    return backup

