def status(self, _: dict[str, Any]) -> dict[str, Any]:
    git = self._run(["git", "status", "--short", "--branch"])
    controller: dict[str, Any] | None = None
    with contextlib.suppress(Exception):
        controller = self._load_controller_state()
    ollama = self.policy["ollama"]
    return {
        "ok": True,
        "action": "governed_executor_status",
        "executor_version": EXECUTOR_VERSION,
        "repository_root": str(self.repo),
        "policy_path": str(Path(os.environ.get("MORENO_OPERATOR_POLICY", str(DEFAULT_POLICY)))),
        "staging_root": str(self.staging_root.relative_to(self.repo)),
        "backup_root": str(self.backup_root.relative_to(self.repo)),
        "read_only_actions": sorted(READ_ONLY_ACTIONS),
        "state_changing_actions": sorted(STATE_CHANGING_ACTIONS),
        "ollama": {
            "base_url": ollama["base_url"],
            "primary_model": ollama["primary_model"],
            "fallback_model": ollama["fallback_model"],
            "forbidden_models": ollama["forbidden_models"],
        },
        "git_status": git.to_dict(),
        "controller_state": controller,
        "n8n_change_required": bool(self.policy["services"]["n8n_change_required"]),
    }

def preflight(self, req: dict[str, Any]) -> dict[str, Any]:
    checks: list[dict[str, Any]] = []
    for command, args in [
        ("git", ["git", "--version"]),
        ("python", ["python3", "--version"]),
        ("bash", ["bash", "--version"]),
    ]:
        result = self._run(args, timeout=20)
        checks.append({"name": command, "passed": result.returncode == 0, "result": result.to_dict()})
    repo_ok = (self.repo / ".git").exists() and self._run(["git", "rev-parse", "--is-inside-work-tree"]).stdout.strip() == "true"
    checks.append({"name": "repository", "passed": repo_ok})
    controller_ok = False
    controller_detail: dict[str, Any] = {}
    try:
        state = self._load_controller_state()
        current = state.get("current_job_id")
        controller_ok = isinstance(current, str) and self._job_path(current).is_file()
        controller_detail = {"state": state, "current_job_exists": controller_ok}
    except Exception as exc:
        controller_detail = {"error": str(exc)}
    checks.append({"name": "controller", "passed": controller_ok, "detail": controller_detail})
    if req.get("probe_ollama", True):
        try:
            tags = self._ollama_tags(timeout=min(int(req.get("timeout_seconds", 30)), 60))
            names = {m.get("name") or m.get("model") for m in tags}
            primary = self.policy["ollama"]["primary_model"]
            fallback = self.policy["ollama"]["fallback_model"]
            passed = primary in names and fallback in names
            checks.append({"name": "ollama_models", "passed": passed, "models": sorted(n for n in names if n)})
        except Exception as exc:
            checks.append({"name": "ollama_models", "passed": False, "error": str(exc)})
    passed = all(bool(item.get("passed")) for item in checks)
    return {"ok": passed, "action": "governed_preflight", "checks": checks}

